/*
*********************************************************************************************************
*                                           BCH_8Bit_Calc()
*
* Description : Calculate 8-bit BCH code for 512-byte data buffer.
*
* Argument(s) : p_buf       Pointer to buffer that contains the data.
*
*               len         Length of buffer, in octets; MUST be between 512 & 528, inclusive.
*
*               p_ecc       Pointer to (13 byte) buffer that will receive BCH code (see Note #1a).
*
*               p_err       Pointer to variable that will receive the return error code from this function :
*
*                               ECC_ERR_NONE           BCH code calculated.
*                               ECC_ERR_INVALID_LEN    Argument 'len' passed an invalid length.
*                               ECC_ERR_NULL_PTR       Argument 'p_buf' or 'p_ecc' passed a NULL pointer.
*
* Return(s)   : none.
*
* Caller(s)   : Application.
*
* Note(s)     : (1) The return parameter 'p_ecc' must point to a valid 13-byte buffer.
*
*               (2) The 104-bit BCH code is stored in the 13-byte buffer.
*
*               (3) Data buffers larger than 512 bytes should be divided into 512-byte segments, with
*                   the ECCs calculated for the individual segments concatenated to form the ECC for the
*                   entire buffer.
*********************************************************************************************************
*/

#if (ECC_BCH_8BIT_CFG_OPTIMIZE_ASM_EN == DEF_DISABLED)
void  BCH_8Bit_Calc (void        *p_buf,
                     CPU_SIZE_T   len,
                     CPU_INT08U  *p_ecc,
                     CPU_ERR     *p_err)
{
    CPU_SIZE_T   nbr_octets;
    CPU_INT08U   ix;
    CPU_INT08U  *p_buf_08;
    CPU_INT32U   ecc0;
    CPU_INT32U   ecc1;
    CPU_INT32U   ecc2;
    CPU_INT32U   ecc3;


#if (ECC_BCH_8BIT_CFG_ARG_CHK_EXT_EN == DEF_ENABLED)            /* ------------------- VALIDATE ARGS ------------------ */
    if (p_ecc == (CPU_INT08U *)0) {                             /* Validate ECC ptr (see Note #1a).                     */
       *p_err = ECC_ERR_NULL_PTR;
        return;
    }
    if (p_buf == (void *)0) {                                   /* Validate buf ptr.                                    */
        Mem_Clr((void *)p_ecc, BCH_n_MINUS_k_octet);
       *p_err = ECC_ERR_NULL_PTR;
        return;
    }
    if ((len < BCH_NBR_OCTETS_MIN) ||                           /* Validate len.                                        */
        (len > BCH_NBR_OCTETS_MAX)) {
        Mem_Clr((void *)p_ecc, BCH_n_MINUS_k_octet);
       *p_err = ECC_ERR_INVALID_LEN;
        return;
    }
#endif



                                                                /* ------------------- CALC BCH CODE ------------------ */
    p_buf_08   = (CPU_INT08U *)p_buf;
    nbr_octets =  0u;

    ecc0       =  0u;
    ecc1       =  0u;
    ecc2       =  0u;
    ecc3       =  0u;

                                                                /* Calc over data.                                      */
    while (nbr_octets < len) {
        ix   = ((CPU_INT08U)ecc3 & DEF_INT_08_MASK) ^ *p_buf_08;/* ix  = (((ecc >> 96) ^ datum) & 0x00FF);              */
                                                                /* ecc = gen_tbl[ix] ^ (ecc << 8);                      */
        ecc3 = (                                ((ecc2 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)  ^ BCH_8Bit_GenTbl[(ix * 4u) + 3u]);
        ecc2 = (((ecc2 << DEF_OCTET_NBR_BITS) | ((ecc1 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)) ^ BCH_8Bit_GenTbl[(ix * 4u) + 2u]);
        ecc1 = (((ecc1 << DEF_OCTET_NBR_BITS) | ((ecc0 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)) ^ BCH_8Bit_GenTbl[(ix * 4u) + 1u]);
        ecc0 = ( (ecc0 << DEF_OCTET_NBR_BITS)                                                            ^ BCH_8Bit_GenTbl[(ix * 4u) + 0u]);

        nbr_octets++;
        p_buf_08++;
    }

                                                                /* Calc over extra octets.                              */
    while (nbr_octets < BCH_NBR_OCTETS_MAX) {
        ix   = ((CPU_INT08U)ecc3 & DEF_INT_08_MASK) ^ 0x00u;    /* ix  = (((ecc >> 96) ^ datum) & 0x00FF);              */
                                                                /* ecc = gen_tbl[ix] ^ (ecc << 8);                      */
        ecc3 = (                                ((ecc2 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)  ^ BCH_8Bit_GenTbl[(ix * 4u) + 3u]);
        ecc2 = (((ecc2 << DEF_OCTET_NBR_BITS) | ((ecc1 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)) ^ BCH_8Bit_GenTbl[(ix * 4u) + 2u]);
        ecc1 = (((ecc1 << DEF_OCTET_NBR_BITS) | ((ecc0 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)) ^ BCH_8Bit_GenTbl[(ix * 4u) + 1u]);
        ecc0 = ( (ecc0 << DEF_OCTET_NBR_BITS)                                                            ^ BCH_8Bit_GenTbl[(ix * 4u) + 0u]);

        nbr_octets++;
    }

    p_ecc[12] = (CPU_INT08U)(ecc0 >> (0u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[11] = (CPU_INT08U)(ecc0 >> (1u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[10] = (CPU_INT08U)(ecc0 >> (2u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[9]  = (CPU_INT08U)(ecc0 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;

    p_ecc[8]  = (CPU_INT08U)(ecc1 >> (0u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[7]  = (CPU_INT08U)(ecc1 >> (1u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[6]  = (CPU_INT08U)(ecc1 >> (2u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[5]  = (CPU_INT08U)(ecc1 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;

    p_ecc[4]  = (CPU_INT08U)(ecc2 >> (0u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[3]  = (CPU_INT08U)(ecc2 >> (1u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[2]  = (CPU_INT08U)(ecc2 >> (2u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[1]  = (CPU_INT08U)(ecc2 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;

    p_ecc[0]  = (CPU_INT08U)(ecc3 >> (0u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
}
#endif


/*
*********************************************************************************************************
*                                           BCH_8Bit_CalcEx()
*
* Description : Calculate 8-bit BCH code for 512-byte data buffer & previous BCH code.
*
* Argument(s) : p_buf       Pointer to buffer that contains the data.
*
*               len         Length of buffer, in octets; MUST be between 512 & 528, inclusive.
*
*               p_ecc_chk   Pointer to (13 byte) buffer that contains the BCH code to check.
*
*               p_ecc       Pointer to (13 byte) buffer that will receive BCH code (see Note #1a).
*
*               p_err       Pointer to variable that will receive the return error code from this function :
*
*                               ECC_ERR_NONE        BCH code calculated.
*                               ECC_ERR_INVALID_LEN    Argument 'len' passed an invalid length.
*                               ECC_ERR_NULL_PTR    Argument 'p_buf', 'p_ecc_chk' or 'p_ecc' passed a
*                                                       NULL pointer.
*
* Return(s)   : none.
*
* Caller(s)   : Application.
*
* Note(s)     : (1) The return parameter 'p_ecc' must point to a valid 13-byte buffer.
*
*               (2) The 104-bit BCH code is stored in the 13-byte buffer.
*
*               (3) Data buffers larger than 512 bytes should be divided into 512-byte segments, with
*                   the ECCs calculated for the individual segments concatenated to form the ECC for the
*                   entire buffer.
*********************************************************************************************************
*/

#if (ECC_BCH_8BIT_CFG_OPTIMIZE_ASM_EN == DEF_DISABLED)
void  BCH_8Bit_CalcEx (void        *p_buf,
                       CPU_SIZE_T   len,
                       CPU_INT08U  *p_ecc_chk,
                       CPU_INT08U  *p_ecc,
                       CPU_ERR     *p_err)
{
    CPU_SIZE_T   nbr_octets;
    CPU_INT08U   ix;
    CPU_INT08U  *p_buf_08;
    CPU_INT32U   ecc0;
    CPU_INT32U   ecc1;
    CPU_INT32U   ecc2;
    CPU_INT32U   ecc3;


#if (ECC_BCH_8BIT_CFG_ARG_CHK_EXT_EN == DEF_ENABLED)            /* ------------------- VALIDATE ARGS ------------------ */
    if (p_ecc == (CPU_INT08U *)0) {                             /* Validate ECC (see Note #1a).                         */
       *p_err = ECC_ERR_NULL_PTR;
        return;
    }
    if (p_ecc_chk == (CPU_INT08U *)0) {                         /* Validate chk ECC.                                    */
        Mem_Clr((void *)p_ecc, BCH_n_MINUS_k_octet);
       *p_err = ECC_ERR_NULL_PTR;
        return;
    }
    if (p_buf == (void *)0) {                                   /* Validate buf ptr.                                    */
        Mem_Clr((void *)p_ecc, BCH_n_MINUS_k_octet);
       *p_err = ECC_ERR_NULL_PTR;
        return;
    }
    if ((len < BCH_NBR_OCTETS_MIN) ||                           /* Validate len.                                        */
        (len > BCH_NBR_OCTETS_MAX)) {
        Mem_Clr((void *)p_ecc, BCH_n_MINUS_k_octet);
       *p_err = ECC_ERR_INVALID_LEN;
        return;
    }
#endif



                                                                /* ------------------- CALC BCH CODE ------------------ */
    p_buf_08   = (CPU_INT08U *)p_buf;
    nbr_octets =  0u;

    ecc0       =  0u;
    ecc1       =  0u;
    ecc2       =  0u;
    ecc3       =  0u;

                                                                /* Calc over data.                                      */
    while (nbr_octets < len) {
        ix   = ((CPU_INT08U)ecc3 & DEF_INT_08_MASK) ^ *p_buf_08;/* ix  = (((ecc >> 96) ^ datum) & 0x00FF);              */
                                                                /* ecc = gen_tbl[ix] ^ (ecc << 8);                      */
        ecc3 = (                                ((ecc2 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)  ^ BCH_8Bit_GenTbl[(ix * 4u) + 3u]);
        ecc2 = (((ecc2 << DEF_OCTET_NBR_BITS) | ((ecc1 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)) ^ BCH_8Bit_GenTbl[(ix * 4u) + 2u]);
        ecc1 = (((ecc1 << DEF_OCTET_NBR_BITS) | ((ecc0 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)) ^ BCH_8Bit_GenTbl[(ix * 4u) + 1u]);
        ecc0 = ( (ecc0 << DEF_OCTET_NBR_BITS)                                                            ^ BCH_8Bit_GenTbl[(ix * 4u) + 0u]);

        nbr_octets++;
        p_buf_08++;
    }

                                                                /* Calc over extra octets.                              */
    while (nbr_octets < BCH_NBR_OCTETS_MAX) {
        ix   = ((CPU_INT08U)ecc3 & DEF_INT_08_MASK) ^ 0x00u;    /* ix  = (((ecc >> 96) ^ datum) & 0x00FF);              */
                                                                /* ecc = gen_tbl[ix] ^ (ecc << 8);                      */
        ecc3 = (                                ((ecc2 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)  ^ BCH_8Bit_GenTbl[(ix * 4u) + 3u]);
        ecc2 = (((ecc2 << DEF_OCTET_NBR_BITS) | ((ecc1 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)) ^ BCH_8Bit_GenTbl[(ix * 4u) + 2u]);
        ecc1 = (((ecc1 << DEF_OCTET_NBR_BITS) | ((ecc0 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)) ^ BCH_8Bit_GenTbl[(ix * 4u) + 1u]);
        ecc0 = ( (ecc0 << DEF_OCTET_NBR_BITS)                                                            ^ BCH_8Bit_GenTbl[(ix * 4u) + 0u]);

        nbr_octets++;
    }

    nbr_octets = BCH_n_MINUS_k_octet;

                                                                    /* Calc over prev ECC.                              */
    while (nbr_octets > 0u) {
        ix   = ((CPU_INT08U)ecc3 & DEF_INT_08_MASK) ^ *p_ecc_chk;   /* ix  = (((ecc >> 96) ^ datum) & 0x00FF);          */
                                                                    /* ecc = gen_tbl[ix] ^ (ecc << 8);                  */
        ecc3 = (                                ((ecc2 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)  ^ BCH_8Bit_GenTbl[(ix * 4u) + 3u]);
        ecc2 = (((ecc2 << DEF_OCTET_NBR_BITS) | ((ecc1 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)) ^ BCH_8Bit_GenTbl[(ix * 4u) + 2u]);
        ecc1 = (((ecc1 << DEF_OCTET_NBR_BITS) | ((ecc0 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK)) ^ BCH_8Bit_GenTbl[(ix * 4u) + 1u]);
        ecc0 = ( (ecc0 << DEF_OCTET_NBR_BITS)                                                            ^ BCH_8Bit_GenTbl[(ix * 4u) + 0u]);

        nbr_octets--;
        p_ecc_chk++;
    }


    p_ecc[12] = (CPU_INT08U)(ecc0 >> (0u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[11] = (CPU_INT08U)(ecc0 >> (1u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[10] = (CPU_INT08U)(ecc0 >> (2u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[9]  = (CPU_INT08U)(ecc0 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;

    p_ecc[8]  = (CPU_INT08U)(ecc1 >> (0u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[7]  = (CPU_INT08U)(ecc1 >> (1u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[6]  = (CPU_INT08U)(ecc1 >> (2u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[5]  = (CPU_INT08U)(ecc1 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;

    p_ecc[4]  = (CPU_INT08U)(ecc2 >> (0u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[3]  = (CPU_INT08U)(ecc2 >> (1u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[2]  = (CPU_INT08U)(ecc2 >> (2u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
    p_ecc[1]  = (CPU_INT08U)(ecc2 >> (3u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;

    p_ecc[0]  = (CPU_INT08U)(ecc3 >> (0u * DEF_OCTET_NBR_BITS)) & DEF_INT_08_MASK;
}
#endif


/*
*********************************************************************************************************
*                                           BCH_8Bit_Chk()
*
* Description : Check previously computed 8-bit BCH code against current data for 512-byte buffer.
*
* Argument(s) : p_buf           Pointer to buffer that contains the data.
*
*               len             Length of buffer, in octets; MUST be between 512 & 528, inclusive.
*
*               p_ecc           Pointer to (13 byte) buffer that contains the BCH code.
*
*               err_addr_tbl    Table that will receive the addresses of any errors.
*
*               max_errs        Size of 'err_addr_tbl'; the maximum number of error locations that can
*                               be returned.
*
*               p_err           Pointer to variable that will receive the return error code from this function :
*
*                                   ECC_ERR_NONE              BCH code verified.
*                                   ECC_ERR_CORRECTABLE       Correctable   error detected in data.
*                                   ECC_ERR_ECC_CORRECTABLE   Correctable   error detected in ECC; correctable
*                                                                 errors may exist in data.
*                                   ECC_ERR_INVALID_ARG       Argument 'max_errs' not 0 & less than 8.
*                                   ECC_ERR_INVALID_LEN       Argument 'len' passed an invalid length.
*                                   ECC_ERR_NULL_PTR          Argument 'p_buf', 'p_ecc' or
*                                                                 'err_addr_tbl' passed a NULL pointer.
*                                   ECC_ERR_UNCORRECTABLE     Uncorrectable error detected.
*
* Return(s)   : The number of bit errors in the data.
*
* Caller(s)   : Application.
*
* Note(s)     : (1) If correctable error(s) are found, 'err_addr_tbl[n].AddrBit' & 'err_addr_tbl[n].AddrOctet'
*                   will specify the location(s) of the bit error(s).  To correct any error(s), the caller
*                   should complement the bit(s) :
*
*                       err_cnt = BCH_8Bit_Chk(&buf[0],
*                                              &bch_prev[0],
*                                              &err_addr_tbl[0],
*                                               8,
*                                              &err);
*
*                       if ((err == ECC_ERR_CORRECTABLE) ||
*                           (err == ECC_ERR_ECC_CORRECTABLE)) {
*                           for (i = 0; i < err_cnt; i++) {
*                               buf[err_addr_tbl[i].AddrOctet] ^= DEF_BIT(err_addr_tbl[i].AddrBit);
*                           }
*                       }
*
*               (2) (a) The maximum number of errors that can be corrected is 8, so 'max_errs' should be 8.
*
*                   (b) An uncorrectable error is one in which 9 or more bits of the data have changed.
*                       & the error is detectable.
*
*                   (c) If more than 8 bits of the data have changed, the error MAY be misdiagnosed as
*                       a correctable error.
*
*               (3) (a) The input vector r(X) is formed by concatenating
*
*                       (1) 3991 zero bits;
*                       (2) 4096 data bits; and
*                       (3)  104 ECC  bits.
*
*                       The zero bits have no affect on the computation.
*
*                   (b) The t odd syndrome components are computed by substituting odd powers of alpha
*                       into the input vector :
*
*                           Si = r(alpha^i)
*
*                       If the input vector is divided by the minimum polynomial phii(X) of alpha^i
*
*                           r(X) = ai(X)*phii(X) + bi(X)
*
*                       So the syndrome components can be calculated
*
*                           Si = r(alpha^i) = bi(alpha^i)
*
*                   (c) The t even syndrome components are computed from predecessor components using
*
*                           S(2i) = Si˛
*
*                   (d) The 'syndrome[]' array contains an extra item (item 0) which is unused.  This allows
*                       the syndrome components S1..S16 to be placed into 'syndrome[0]'..'syndrome[16]'.
*
*               (4) The inverse of an element of GF(2^m) can be calculated
*
*                       beta^-1 = beta^-1 * 1 = beta^-1 * beta^(2^m - 1) = beta^(2^m - 2)
*
*                   If beta is expressed in power representation
*
*                       beta^-1 = (alpha^i)^(-1) = alpha^-i) = alpha^-i * alpha^(2^m - 1) = alpha^(2^m-i-1)
*
*               (5) Berlekamp's iterative algorithm is used to find the error-locating polynomial.
*
*                   (a) A decoding table to track previous iterations is initialized
*
*                      -----------------------------------------------------------------
*                         mu       sigma(mu)       d(mu)       l(mu)       2*mu - l(mu)
*                      -----------------------------------------------------------------
*                        -1/2           1             1          0             -1
*                          0           1             S1         0              0
*                          1
*                          2
*                          .
*                          .
*                          .
*                          t
*
*                       (1) sigma(mu) is sn error-locating polynomial satisfying the first mu syndromes.
*
*                       (2) d(mu) is the discrepancy, used to determine the next error-locating polynomial.
*
*                       (3) l(mu) is the degree of sigma(mu).
*
*                   (b) In each iteration, another row of the decoding table is filled based on previous row(s) :
*
*                       (1) If d(mu) == 0, then sigma(mu+1) = sigma(mu)
*                                               l(mu+1)     = l(mu)
*
*                       (2) Otherwise, we must find a row rho prior to the muth row such that d(rho) != 0
*                           and rho - l(rho) is maximized.
*
*                               sigma(mu+1) = sigma(mu) + d(mu) * d(rho)^-1 * X^(mu-rho) * sigma(rho)
*                               l(mu+1)     = max(l(mu), l(rho)+mu-rho)
*
*                           (A) See Note #4.
*
*                           (B) The first mu-rho terms in sigma(mu) will become the first mu-rho terms in sigma(mu + 1).
*
*                           (C) If the degree of sigma(mu+1), l(mu+1), will be greater than 5, the
*                               received vector has too many errors to correct.
*
*                       (3) In either case
*
*                               d(mu+1) = S(mu+2) + sigma(mu+1)[1] * S(mu+1) + ... + sigma(mu+1)[l(mu+1)] * S(mu+2-l(mu+1))
*
*                           (A) This need not be computed for the final entry in the table.
*
*                   (c) The 'sigma' and 'd' members of 'BCH_DECODE_TBL_ENTRY' store the logarithm
*                       of GF elements.  If the GF element is zero, then DEF_INT_16U_MAX_VAL is used.
*
*               (6) A Chien search is used to determine the bits error locations from the error-locating
*                   polynomial.  The search proceeds from the final bit to the first bit; consequently,
*                   the loop variable must be subtracted from 'n' to get the bit location.
*
*                   (a) The ECC and data constitute the 'valid' bits of the input vector, which are padded
*                       upon BCH code computation with empty (zero) bits to for the necessary length of
*                       the vector, n = 2^m - 1.  The computational method causes the empty bits to occupy
*                       intervals 0-116 and 4317-8191, which need not be searched by the algorithm.  The
*                       empty intervals, in terms of the loop variable, are 0-3874 and 8074-8191.
*
*                   (b) Because of the order in which data bytes are used in computing the BCH code,
*                       the bit locations require adjustment to yield buffer bit locations :
*
*                          117 bit location = 1st bit of  12th byte of ECC
*                          124 bit location = 7th bit of  12th byte of ECC
*                          213 bit location = 1st bit of   0th byte of ECC
*                          220 bit location = 7th bit of   0th byte of ECC
*                          221 bit location = 1st bit of 511th byte of data
*                          228 bit location = 1st bit of 510th byte of data
*                           .
*                           .
*                         4309 bit location = 1st bit of   0th byte of data
*                         4316 bit location = 7th bit of   0th byte of data
*
*               (7) The error-locating polynomial is divided by the newly-found linear root; by reducing
*                   the degree of the polynomial, the calculation of polynomial values is expedited & the
*                   final quadratic polynomial (once all but two errors are located) can be directly
*                   evaluated.
*
*                   (a) "Synthetic division" is used to determine the dividend.
*
*                   (b) The dividend is "normalized" by dividing by the constant term; consequently, the
*                       constant term will be 1 (& its logarithm will be 0).
*
*                   (c) The state of the Chien search must be restored by multiplying the jth coefficient
*                       of the error-locating by alpha^((loop_ctr + 1) * j).
*********************************************************************************************************
*/

CPU_INT08U  BCH_8Bit_Chk (void          *p_buf,
                          CPU_SIZE_T     len,
                          CPU_INT08U    *p_ecc,
                          ECC_ERR_ADDR   err_addr_tbl[],
                          CPU_INT08U     max_errs,
                          CPU_ERR       *p_err)
{
    BCH_DECODE_TBL_ENTRY  decode_tbl[BCH_t + 2u];
    CPU_INT08U            ecc[BCH_n_MINUS_k_octet];
    BCH_GF_POLY_PWR       srch_vect[BCH_t + 1u];
    BCH_GF_POLY_PWR       syndrome[(BCH_t * 2u) + 1u];      /* See Note #3d.                                        */
    CPU_INT16U            i;
    CPU_INT16U            i_init;
    CPU_INT16U            j;
    CPU_INT16S            k;
    CPU_INT16S            krho;
    CPU_INT16S            k_start;
    CPU_BOOLEAN           clr;
    BCH_GF_POLY_PWR       d;
    BCH_GF_POLY_PWR       d_addend;
    CPU_INT16U            deg;
    CPU_INT16U            err_cnt;
    CPU_INT16U            err_ecc_cnt;
    CPU_INT16U            err_loc;
    BCH_GF_POLY           exp1;
    BCH_GF_POLY           exp2;
    CPU_INT16S            l;
    CPU_INT16S            l_cmp;
    CPU_INT16S            mu;
    CPU_INT16S            mu_minus_l_cmp;
    CPU_INT16S            mu_minus_l_cmp_new;
    CPU_INT16S            rho;
    CPU_INT16S            rho_cmp;
    CPU_INT16S            rho_dbl;
    BCH_GF_POLY_PWR       sigma;
    BCH_GF_POLY           sum;
    BCH_GF_POLY_PWR       sum_log;
#if (BCH_FACTOR_OPT_EN == DEF_ENABLED)
    BCH_GF_POLY           prod;
    BCH_GF_POLY_PWR       prod_log;
#endif


#if (ECC_BCH_8BIT_CFG_ARG_CHK_EXT_EN == DEF_ENABLED)            /* ------------------- VALIDATE ARGS ------------------ */
    if (max_errs > 0u) {                                        /* Validate err cnt.                                    */
        if (err_addr_tbl == (ECC_ERR_ADDR *)0) {
           *p_err = ECC_ERR_NULL_PTR;
            return (0u);
        }

        if (max_errs < BCH_t) {
           *p_err = ECC_ERR_INVALID_ARG;
            return (0u);
        }
    }
    if (p_buf == (void *)0) {                                   /* Validate buf ptr.                                    */
       *p_err = ECC_ERR_NULL_PTR;
        return (0u);
    }
    if (p_ecc == (CPU_INT08U *)0) {                             /* Validate ECC ptr.                                    */
       *p_err = ECC_ERR_NULL_PTR;
        return (0u);
    }
    if ((len < BCH_NBR_OCTETS_MIN) ||                           /* Validate len.                                        */
        (len > BCH_NBR_OCTETS_MAX)) {
       *p_err = ECC_ERR_INVALID_LEN;
        return (0u);
    }
#endif



                                                                /* ----------------- COMPUTE SYNDROME ----------------- */
    BCH_8Bit_CalcEx(p_buf, len, p_ecc, &ecc[0], p_err);

    clr = DEF_YES;                                              /* Chk if no errs.                                      */
    for (i = 0u; i < BCH_n_MINUS_k_octet; i++) {
        if (ecc[i] != 0u) {
            clr = DEF_NO;
        }
    }
    if (clr == DEF_YES) {                                       /* Rtn if no errs.                                      */
       *p_err = ECC_ERR_NONE;
        return (0u);
    }

    BCH_CalcSyndrome(&ecc[0], &syndrome[0]);




                                                                /* -------------- FIND ERR-LOCATING POLY -------------- */
    for (i = 0u; i < BCH_t + 2u; i++) {                         /* Clr decode entry tbl.                                */
        for (j = 0u; j < BCH_t + 1u; j++) {                     /* Set all sigma[i] = log(0).                           */
            decode_tbl[i].sigma[j] = DEF_INT_16U_MAX_VAL;
        }
        decode_tbl[i].d = DEF_INT_16U_MAX_VAL;                  /* Set all d[i]     = log(0).                           */
        decode_tbl[i].l = 0;
    }


    decode_tbl[0].sigma[0] =  0u;                               /* log(1)                                               */
    decode_tbl[0].d        =  0u;                               /* log(1)                                               */
    decode_tbl[0].l        =  0;

    decode_tbl[1].sigma[0] =  0u;                               /* log(1)                                               */
    decode_tbl[1].d        =  syndrome[1];
    decode_tbl[1].l        =  0;

    mu        = 0;
    while (mu < (CPU_INT16S)BCH_t) {
        if (decode_tbl[(mu) + 1].d == DEF_INT_16U_MAX_VAL) {    /* If d(mu) == 0 ...                                    */
            for (l = 0; l < decode_tbl[(mu) + 1].l + 1; l++) {  /* ... sigma(mu+1) = sigma(mu) ...                      */
                decode_tbl[(mu+1) + 1].sigma[l] = decode_tbl[(mu) + 1].sigma[l];
            }
            decode_tbl[(mu+1) + 1].l = decode_tbl[(mu) + 1].l;  /* ... l(mu+1)     = l(mu).                             */


        } else {                                                /* If d(mu) != 0 ...                                    */
            mu_minus_l_cmp = -1;
            rho_cmp        = -1;
            for (rho = 0; rho < mu; rho++) {
                                                                /* ... Find rho such that d[rho] is not zero ...        */
                if (decode_tbl[(rho) + 1].d != DEF_INT_16U_MAX_VAL) {
                                                                /* ... & rho - l[rho] is largest             ...        */
                    mu_minus_l_cmp_new  = (CPU_INT16S)((2 * rho) - decode_tbl[(rho) + 1].l);
                    if (mu_minus_l_cmp <= mu_minus_l_cmp_new) {
                        mu_minus_l_cmp  = mu_minus_l_cmp_new;
                        rho_cmp         =  rho;
                    }
                }
            }
            rho                      =  rho_cmp;
            rho_dbl                  = (rho == -1) ? (rho) : ((CPU_INT16S)(2 * rho));
            l_cmp                    = (CPU_INT16S)(decode_tbl[(rho) + 1].l + (2 * mu) - rho_dbl);
            decode_tbl[(mu+1) + 1].l = DEF_MAX(decode_tbl[(mu) + 1].l, l_cmp);

            if (decode_tbl[(mu+1) + 1].l > (CPU_INT16S)BCH_t) { /* Uncorrectable errors (see Note #5b2C).               */
               *p_err = ECC_ERR_UNCORRECTABLE;
                return (0u);
            }

                                                                /* ... calc sigma.                                      */

                                                                /* Calc d[mu] * d[rho]^-1 (see Note #4).                */
            d = decode_tbl[(mu) + 1].d;
            if (decode_tbl[(rho) + 1].d != DEF_INT_16U_MAX_VAL) {
                d += BCH_n - decode_tbl[(rho) + 1].d;
                d  = BCH_WRAP(d);
            }

            for (k = 0; k < (2 * mu) - rho_dbl; k++) {          /* Copy mu-rho terms from prev (see Note #5b2B) ...     */
                decode_tbl[(mu+1) + 1].sigma[k] = decode_tbl[(mu) + 1].sigma[k];
            }
                                                                /* ... then calc final terms.                           */
            k_start = (CPU_INT16S)((2 * mu) - rho_dbl);
            for (k = k_start; k < (CPU_INT16S)BCH_t + 1; k++) {
                krho = (CPU_INT16S)((k - (2 * mu)) + rho_dbl);
                                                                /* If prev kth term is zero, use sigma[rho] term.       */
                if (decode_tbl[(mu) + 1].sigma[k] == DEF_INT_16U_MAX_VAL) {
                    if (decode_tbl[(rho) + 1].sigma[krho] == DEF_INT_16U_MAX_VAL) {
                        decode_tbl[(mu+1) + 1].sigma[k] = DEF_INT_16U_MAX_VAL;
                    } else {
                        sigma                           = decode_tbl[(rho) + 1].sigma[krho] + d;
                        sigma                           = BCH_WRAP(sigma);
                        decode_tbl[(mu+1) + 1].sigma[k] = sigma;
                    }

                                                                /* If sigma[rho] term is zero, use prev ith term.       */
                } else if (decode_tbl[(rho) + 1].sigma[krho] == DEF_INT_16U_MAX_VAL) {
                    decode_tbl[(mu+1) + 1].sigma[k] = decode_tbl[(mu) + 1].sigma[k];

                } else {                                        /* If both prev term & sigma[rho] term nonzero, add.    */
                    sigma = decode_tbl[(rho) + 1].sigma[krho] + d;
                    sigma = BCH_WRAP(sigma);

                    if (sigma == decode_tbl[(mu) + 1].sigma[k]) {
                        sigma =  DEF_INT_16U_MAX_VAL;
                    } else {
                        exp1  =  BCH_GF_Tbl[sigma];
                        exp2  =  BCH_GF_Tbl[decode_tbl[(mu) + 1].sigma[k]];
                        sum   = (exp1 ^ exp2);
                        sigma =  BCH_GF_LogTbl[sum];
                    }

                    decode_tbl[(mu+1) + 1].sigma[k] = sigma;
                }
            }
        }

        if (mu != (CPU_INT16S)BCH_t - 1) {                      /* Skip for final entry (see Note #5b3A).               */
            d = syndrome[(2 * mu) + 3];
            for (l = 0; l <= decode_tbl[(mu+1) + 1].l - 1; l++) {
                if (decode_tbl[(mu+1) + 1].sigma[1 + l] != DEF_INT_16U_MAX_VAL) {
                    d_addend = decode_tbl[(mu+1) + 1].sigma[1 + l] + syndrome[(2 * mu) + 2 - l];
                    d_addend = BCH_WRAP(d_addend);

                    if (d == d_addend) {
                        d =  DEF_INT_16U_MAX_VAL;
                    } else {
                        exp1 =  BCH_GF_Tbl[d];
                        exp2 =  BCH_GF_Tbl[d_addend];
                        sum  = (exp1 ^ exp2);
                        d    =  BCH_GF_LogTbl[sum];
                    }
                }
            }
            decode_tbl[(mu+1) + 1].d = d;
        }

        mu++;
    }



                                                                /* ---------------- FIND ERR LOCATIONS ---------------- */
    if (decode_tbl[BCH_t + 1u].l < 0) {                         /* Validate err-locating poly deg.                      */
       *p_err = ECC_ERR_UNCORRECTABLE;
        return (0u);
    }

    err_cnt     =  0u;
    err_ecc_cnt =  0u;
    deg         = (CPU_INT16U)decode_tbl[BCH_t + 1u].l;
    if (deg == 1u) {                                            /* Solve linear eq.                                     */
        BCH_CalcErrAddrLinear( decode_tbl[BCH_t + 1u].sigma[0],
                               decode_tbl[BCH_t + 1u].sigma[1],
                              &err_addr_tbl[err_cnt],
                               p_err);

        switch (*p_err) {
            case ECC_ERR_ECC_CORRECTABLE:
                 err_cnt = 0u;
                 break;

            case ECC_ERR_CORRECTABLE:
                 err_cnt = 1u;
                 break;

            default:
            case ECC_ERR_UNCORRECTABLE:
                 err_cnt = 0u;
                 break;
        }

        return ((CPU_INT08U)err_cnt);
    }


#if (BCH_QUAD_OPT_EN == DEF_ENABLED)
    if (deg == 2u) {                                            /* Solve quad eq.                                       */
        err_cnt = BCH_CalcErrAddrQuad( decode_tbl[BCH_t + 1u].sigma[0],
                                       decode_tbl[BCH_t + 1u].sigma[1],
                                       decode_tbl[BCH_t + 1u].sigma[2],
                                      &err_addr_tbl[0],
                                       p_err);

        return ((CPU_INT08U)err_cnt);
    }
#endif

    i_init = 0u;
    for (j = 0u; j <= BCH_t; j++) {                             /* Set init srch vect.                                  */
                                                                /* See Note #6a.                                        */
        if (j <= deg) {
            srch_vect[j] = decode_tbl[BCH_t + 1u].sigma[j];
            if (srch_vect[j] != DEF_INT_16U_MAX_VAL) {
                srch_vect[j] += i_init;
                srch_vect[j]  = BCH_WRAP(srch_vect[j]);

                i_init       += BCH_LOOP_CTR_MIN;
                i_init        = BCH_WRAP(i_init);
            }
        } else {
            srch_vect[j] = DEF_INT_16U_MAX_VAL;
        }
    }

                                                                /* For each bit i (see Note #6) ...                     */
    for (i = BCH_LOOP_CTR_MIN; i <= BCH_LOOP_CTR_MAX; i++) {
        sum  = 1u;
        for (j = 1u; j <= deg; j++) {                           /* ... calc sum & compute next srch vect.               */
            if (srch_vect[j] != DEF_INT_16U_MAX_VAL) {
                sum          ^= BCH_GF_Tbl[srch_vect[j]];
                srch_vect[j] += j;
                srch_vect[j]  = BCH_WRAP(srch_vect[j]);
            }
        }
        if (sum == 0u) {                                        /* If sum 0 ...                                         */
            err_loc = BCH_n - i;                                /* ... err loc found.                                   */
            BCH_CalcErrAddr(err_loc, &err_addr_tbl[err_cnt], p_err);

            switch (*p_err) {
                case ECC_ERR_ECC_CORRECTABLE:
                     err_ecc_cnt++;
                     break;

                case ECC_ERR_CORRECTABLE:
                     err_cnt++;
                     break;

                default:
                case ECC_ERR_UNCORRECTABLE:
                     return (0u);
            }

                                                                /* All errs found.                                      */
            if (err_ecc_cnt + err_cnt >= decode_tbl[BCH_t + 1u].l) {
                break;
            }

#if (BCH_FACTOR_OPT_EN == DEF_ENABLED)
                                                                /* Div err-locating poly by root (see Note #7).         */
            for (j = deg - 1u; j >= 1u; j--) {                  /* Use synth div (see Note #7a).                        */
                prod_log  = i + decode_tbl[BCH_t + 1u].sigma[j + 1u];
                prod_log  = BCH_WRAP(prod_log);

                prod      = BCH_GF_Tbl[prod_log];
                prod     ^= BCH_GF_Tbl[decode_tbl[BCH_t + 1u].sigma[j]];
                sum_log   = BCH_GF_LogTbl[prod];

                decode_tbl[BCH_t + 1u].sigma[j] = sum_log;
            }

            prod_log = decode_tbl[BCH_t + 1u].sigma[1];         /* Shift & normalize poly (see Note #7b).               */
            for (j = 0u; j <= deg - 1u; j++) {
                sum_log = decode_tbl[BCH_t + 1u].sigma[j + 1u] + BCH_n - prod_log;
                sum_log = BCH_WRAP(sum_log);
                decode_tbl[BCH_t + 1u].sigma[j] = sum_log;
            }


            decode_tbl[BCH_t + 1u].sigma[deg] = DEF_INT_16U_MAX_VAL;
            deg--;

#if (BCH_QUAD_OPT_EN == DEF_ENABLED)
            if (deg == 2u) {                                    /* Solve rem quad eq.                                   */
                err_cnt += BCH_CalcErrAddrQuad( decode_tbl[BCH_t + 1u].sigma[0],
                                                decode_tbl[BCH_t + 1u].sigma[1],
                                                decode_tbl[BCH_t + 1u].sigma[2],
                                               &err_addr_tbl[err_cnt],
                                                p_err);

                if (*p_err == ECC_ERR_UNCORRECTABLE) {
                    return (0u);
                }

                if (*p_err == ECC_ERR_CORRECTABLE) {
                    *p_err = (err_ecc_cnt == 0u) ? ECC_ERR_CORRECTABLE : ECC_ERR_ECC_CORRECTABLE;
                }

                return ((CPU_INT08U)err_cnt);
            }
#else
            if (deg == 1) {                                     /* Solve rem linear eq.                                 */
                BCH_CalcErrAddrLinear( decode_tbl[BCH_t + 1].sigma[0],
                                       decode_tbl[BCH_t + 1].sigma[1],
                                      &err_addr_tbl[err_cnt],
                                       p_err);

                if (*p_err == ECC_ERR_UNCORRECTABLE) {
                    return (0u);
                }

                if (*p_err == ECC_ERR_CORRECTABLE) {
                    *p_err = (err_ecc_cnt == 0) ? ECC_ERR_CORRECTABLE : ECC_ERR_ECC_CORRECTABLE;
                     err_cnt++;
                }

                return (err_cnt);
            }
#endif

            i_init = 0u;
            for (j = 0u; j <= deg; j++) {                       /* Return srch state (see Note #7c).                    */
                srch_vect[j] = decode_tbl[BCH_t + 1u].sigma[j];
                if (srch_vect[j] != DEF_INT_16U_MAX_VAL) {
                    srch_vect[j] += i_init;
                    srch_vect[j]  = BCH_WRAP(srch_vect[j]);

                    i_init       += i + 1u;
                    i_init        = BCH_WRAP(i_init);
                }
            }
#endif

        }
    }

    if (err_ecc_cnt + err_cnt < deg) {
       *p_err = ECC_ERR_UNCORRECTABLE;
        return (0u);
    }

   *p_err = (err_ecc_cnt == 0u) ? ECC_ERR_CORRECTABLE : ECC_ERR_ECC_CORRECTABLE;

    return ((CPU_INT08U)err_cnt);
}


/*
*********************************************************************************************************
*                                        BCH_8Bit_Correct()
*
* Description : Check previously computed 8-bit BCH code against current data & correct any error(s), if
*               possible, for 512-byte buffer.
*
* Argument(s) : p_buf       Pointer to buffer that contains the data.
*
*               len         Length of buffer, in octets; MUST be between 512 & 528, inclusive.
*
*               p_ecc       Pointer to (13 byte) buffer that contains the BCH code.
*
*               p_err       Pointer to variable that will receive the return error code from this function :
*
*                               ECC_ERR_NONE              BCH code verified.
*                               ECC_ERR_CORRECTABLE       Correctable   error detected in data.
*                               ECC_ERR_ECC_CORRECTABLE   Correctable   error detected in ECC; correctable
*                                                             errors may exist in data.
*                               ECC_ERR_UNCORRECTABLE     Uncorrectable error detected.
*                               ECC_ERR_NULL_PTR          Argument 'p_buf' or 'p_ecc' or passed a NULL
*                                                             pointer.
*
* Return(s)   : none.
*
* Caller(s)   : Application.
*
* Note(s)     : none.
*********************************************************************************************************
*/

void  BCH_8Bit_Correct (void        *p_buf,
                        CPU_SIZE_T   len,
                        CPU_INT08U  *p_ecc,
                        CPU_ERR     *p_err)
{
    ECC_ERR_ADDR   err_addr_tbl[BCH_t];
    CPU_INT08U     err_cnt;
    CPU_INT08U     i;
    CPU_INT08U    *p_buf_08;


    err_cnt = BCH_8Bit_Chk( p_buf,                              /* Calc BCH code for cur buf.                           */
                            len,
                            p_ecc,
                           &err_addr_tbl[0],
                            BCH_t,
                            p_err);

    if ((*p_err != ECC_ERR_CORRECTABLE) &&
        (*p_err != ECC_ERR_ECC_CORRECTABLE)) {
        return;
    }

                                                                /* Correct err(s).                                      */
    p_buf_08 = (CPU_INT08U *)p_buf;
    for (i = 0u; i < err_cnt; i++) {
        if (err_addr_tbl[i].AddrOctet < len) {
            p_buf_08[err_addr_tbl[i].AddrOctet] ^= (CPU_INT08U)DEF_BIT(err_addr_tbl[i].AddrBit);
        }
    }
}


/*
*********************************************************************************************************
*********************************************************************************************************
*                                           LOCAL FUNCTIONS
*********************************************************************************************************
*********************************************************************************************************
*/

/*
*********************************************************************************************************
*                                       BCH_8Bit_CalcSyndrome()
*
* Description : Calculate syndrome.
*
* Argument(s) : p_ecc       Pointer to buffer that contains the ECC.
*
*               syndrome    Table that will receive the syndrome components.
*
* Return(s)   : none.
*
* Caller(s)   : BCH_8Bit_Chk().
*
* Note(s)     : none.
*********************************************************************************************************
*/

static  void  BCH_CalcSyndrome (CPU_INT08U       *p_ecc,
                                BCH_GF_POLY_PWR   syndrome[])
{
    BCH_GF_POLY      min_poly_rem;
    BCH_GF_POLY_PWR  poly_log;
    CPU_INT08U       i;
    CPU_INT08U       j;


    Mem_Clr((void *)&syndrome[0], sizeof(BCH_GF_POLY_PWR) * ((BCH_t * 2u) + 1u));

    for (i = 0u; i < BCH_t; i++) {
        j                 = (i * 2u) + 1u;                              /* Calc bj(X).                                  */
        min_poly_rem      = BCH_CalcSyndromeRem(&p_ecc[0], BCH_SyndromeGenTblTbl[i]);
        min_poly_rem    >>= (16u - BCH_m);

        if (min_poly_rem != 0u) {
            min_poly_rem = BCH_EvalPoly(min_poly_rem, j);
            poly_log     = BCH_GF_LogTbl[min_poly_rem];                 /* Calc Sj = bj(alpha);                         */
            syndrome[j]  = poly_log;

            while (j <= BCH_t) {
                j          *= 2u;
                poly_log   *= 2u;                                       /* Calc Sj = S(j/2)˛.                           */
                poly_log    = BCH_WRAP(poly_log);
                syndrome[j] = poly_log;
            }
        }
    }
}


/*
*********************************************************************************************************
*                                          BCH_CalcErrAddr()
*
* Description : Calculate error address.
*
* Argument(s) : err_loc         Error location.
*
*               p_err_addr      Pointer to variable that will receive error address.
*
*               p_err           Pointer to variable that will receive the return error code from this function :
*
*                                   ECC_ERR_NONE              No errors exist.
*                                   ECC_ERR_CORRECTABLE       Correctable   error detected in data.
*                                   ECC_ERR_ECC_CORRECTABLE   Correctable   error detected in ECC; correctable
*                                                                 errors may exist in data.
*                                   ECC_ERR_UNCORRECTABLE     Uncorrectable error detected.
*
* Return(s)   : none.
*
* Caller(s)   : BCH_8Bit_Chk(),
*               BCH_CalcErrAddrLinear(),
*               BCH_CalcErrAddrQuad().
*
* Note(s)     : none.
*********************************************************************************************************
*/

static  void  BCH_CalcErrAddr (CPU_INT16U     err_loc,
                               ECC_ERR_ADDR  *p_err_addr,
                               CPU_ERR       *p_err)
{
    CPU_INT08U  err_addr_bit;
    CPU_INT16U  err_addr_octet;


    if ((err_loc < BCH_ERR_LOC_MIN) ||
        (err_loc > BCH_ERR_LOC_MAX)) {
       *p_err = ECC_ERR_UNCORRECTABLE;


    } else {
        err_loc -= BCH_ERR_LOC_MIN;
        if (err_loc <= BCH_n_MINUS_k - 1u) {                /* Err in ECC.                                          */
           *p_err = ECC_ERR_ECC_CORRECTABLE;


        } else {                                            /* Err in data.                                         */
            if (p_err_addr != (ECC_ERR_ADDR *)0) {
                err_addr_bit   =                             (CPU_INT08U) (err_loc - BCH_n_MINUS_k) & 0x07u;
                err_addr_octet = (BCH_NBR_OCTETS_MAX - 1u) - (CPU_INT16U)((err_loc - BCH_n_MINUS_k) >> 3);

                p_err_addr->AddrBit   =  err_addr_bit;
                p_err_addr->AddrOctet = (CPU_SIZE_T)err_addr_octet;
            }
           *p_err = ECC_ERR_CORRECTABLE;
        }
    }
}


/*
*********************************************************************************************************
*                                       BCH_CalcErrAddrLinear()
*
* Description : Calculate error address for linear equation a * X + b.
*
* Argument(s) : b               Constant.
*
*               a               Coefficient of X.
*
*               err_addr_tbl    Table of error addresses.
*
*               p_err           Pointer to variable that will receive the return error code from this function :
*
*                                   ECC_ERR_NONE              No errors exist.
*                                   ECC_ERR_CORRECTABLE       Correctable   error detected in data.
*                                   ECC_ERR_ECC_CORRECTABLE   Correctable   error detected in ECC; correctable
*                                                                 errors may exist in data.
*                                   ECC_ERR_UNCORRECTABLE     Uncorrectable error detected.
*
* Return(s)   : none.
*
* Caller(s)   : BCH_8Bit_Chk().
*
* Note(s)     : none.
*********************************************************************************************************
*/

static  void  BCH_CalcErrAddrLinear (BCH_GF_POLY_PWR   b,
                                     BCH_GF_POLY_PWR   a,
                                     ECC_ERR_ADDR      err_addr_tbl[],
                                     CPU_ERR          *p_err)
{
    BCH_GF_POLY_PWR  b_inv;
    CPU_INT16U       err_loc;


    b_inv   = BCH_n - b;
    err_loc = a + b_inv;
    err_loc = BCH_WRAP(err_loc);

    BCH_CalcErrAddr(err_loc, err_addr_tbl, p_err);
}


/*
*********************************************************************************************************
*                                        BCH_CalcErrAddrQuad()
*
* Description : Calculate error address for quadratic equation a * X˛ + b * X + c.
*
* Argument(s) : c               Constant.
*
*               b               Coefficient of X.
*
*               a               Coefficient of X˛
*
*               err_addr_tbl    Table of error addresses.
*
*               p_err           Pointer to variable that will receive the return error code from this function :
*
*                                   ECC_ERR_NONE              No errors exist.
*                                   ECC_ERR_CORRECTABLE       Correctable   error detected in data.
*                                   ECC_ERR_ECC_CORRECTABLE   Correctable   error detected in ECC; correctable
*                                                                 errors may exist in data.
*                                   ECC_ERR_UNCORRECTABLE     Uncorrectable error detected.
*
* Return(s)   : The number of bit errors.
*
* Caller(s)   : BCH_8Bit_Chk().
*
* Note(s)     : (1) The quadratic formula applicable to equations with real or complex coefficients is
*                   not valid for Galois fields GF(2^n).  Let R(d) be the root of the polynomial
*
*                       X˛ + X + d
*
*                   The roots of the quadratic
*
*                       a*X˛ + b*X + c
*
*                   can be written in terms of R(d) :
*
*                             b       a*c                 b        a*c
*                       X1 = --- * R(-----)         X2 = --- * (R(-----) + 1)
*                             a        b˛                 a         b˛
*
*                   The roots R(d) are pre-computed & stored in the 'BCH_GF_QuadSolTbl[]'.
*********************************************************************************************************
*/

#if (BCH_QUAD_OPT_EN == DEF_ENABLED)
static  CPU_INT16U  BCH_CalcErrAddrQuad (BCH_GF_POLY_PWR   c,
                                         BCH_GF_POLY_PWR   b,
                                         BCH_GF_POLY_PWR   a,
                                         ECC_ERR_ADDR      err_addr_tbl[],
                                         CPU_ERR          *p_err)
{
    BCH_GF_POLY_PWR  quad_lu_log;
    BCH_GF_POLY      quad_lu;
    BCH_GF_POLY_PWR  quad_sol_log;
    BCH_GF_POLY      quad_sol;
    BCH_GF_POLY_PWR  quad_root_1;
    BCH_GF_POLY_PWR  quad_root_2;
    CPU_INT16U       err_cnt;
    CPU_INT16U       err_ecc_cnt;
    CPU_INT16U       err_loc;


    err_cnt     = 0u;
    err_ecc_cnt = 0u;

    quad_lu_log  =  b * 2u;                                     /* b˛                                                   */
    quad_lu_log  =  BCH_WRAP(quad_lu_log);

    quad_lu_log  =  BCH_n - quad_lu_log;                        /* 1/b˛                                                 */
    quad_lu_log +=  a;                                          /* a/b˛                                                 */
    quad_lu_log  =  BCH_WRAP(quad_lu_log);

    quad_lu_log +=  c;                                          /* a*c/b˛                                               */
    quad_lu_log  =  BCH_WRAP(quad_lu_log);

    quad_lu      =  BCH_GF_Tbl[quad_lu_log];
    quad_sol     =  BCH_GF_QuadSolTbl[quad_lu];                 /* R(a*c/b˛)                                            */


    if (quad_sol != 0u) {
                                                                /* ------------------- CALC 1st ROOT ------------------ */
        quad_sol_log  = BCH_GF_LogTbl[quad_sol];
        quad_root_1   = quad_sol_log + b;                       /* b * R(a*c/b˛)                                        */
        quad_root_1   = BCH_WRAP(quad_root_1);
        quad_root_1  += BCH_n - a;                              /* b/a * R(a*c/b˛)                                      */
        quad_root_1   = BCH_WRAP(quad_root_1);

        err_loc       = BCH_n - quad_root_1;
        BCH_CalcErrAddr(err_loc, err_addr_tbl, p_err);

        switch (*p_err) {
            case ECC_ERR_ECC_CORRECTABLE:
                 err_ecc_cnt++;
                 break;

            case ECC_ERR_CORRECTABLE:
                 err_addr_tbl++;
                 err_cnt++;
                 break;

            default:
            case ECC_ERR_UNCORRECTABLE:
                 return (0u);
        }


                                                                /* ------------------- CALC 2nd ROOT ------------------ */
        quad_sol     += 1u;                                     /* R(a*c/b˛) + 1                                        */
        quad_sol_log  = BCH_GF_LogTbl[quad_sol];
        quad_root_2   = quad_sol_log + b;                       /* b * (R(a*c/b˛) + 1)                                  */
        quad_root_2   = BCH_WRAP(quad_root_2);
        quad_root_2  += BCH_n - a;                              /* b/a * (R(a*c/b˛) + 1)                                */
        quad_root_2   = BCH_WRAP(quad_root_2);

        err_loc       = BCH_n - quad_root_2;
        BCH_CalcErrAddr(err_loc, err_addr_tbl, p_err);

        switch (*p_err) {
            case ECC_ERR_ECC_CORRECTABLE:
                 err_ecc_cnt++;
                 break;

            case ECC_ERR_CORRECTABLE:
                 err_cnt++;
                 break;

            default:
            case ECC_ERR_UNCORRECTABLE:
                 return (0u);
        }

       *p_err = (err_ecc_cnt == 0u) ? ECC_ERR_CORRECTABLE : ECC_ERR_ECC_CORRECTABLE;

        return (err_cnt);


    } else {
       *p_err = ECC_ERR_UNCORRECTABLE;
        return (0u);
    }
}
#endif


/*
*********************************************************************************************************
*                                        BCH_CalcSyndromeRem()
*
* Description : Calculate syndrome remainder.
*
* Argument(s) : p_buf       Pointer to buffer.
*
*               aux_tbl     Array that will holds the syndrome generation table.
*
* Return(s)   : none.
*
* Caller(s)   : BCH_CalcSyndrome().
*
* Note(s)     : none.
*********************************************************************************************************
*/

static  BCH_GF_POLY  BCH_CalcSyndromeRem (CPU_INT08U          *p_buf,
                                          const  BCH_GF_POLY   aux_tbl[])
{
    BCH_GF_POLY  rem;
    CPU_INT08U   ix;
    CPU_SIZE_T   buf_len;


    rem     = 0u;
    buf_len = BCH_n_MINUS_k_octet;
    while (buf_len > 0u) {
        ix       = ((CPU_INT08U)((CPU_INT08U)(rem >> DEF_INT_08_NBR_BITS) ^ *p_buf) & DEF_INT_08_MASK);
        rem      = aux_tbl[ix] ^ (BCH_GF_POLY)(rem << 8);
        p_buf   += sizeof(CPU_INT08U);
        buf_len -= sizeof(CPU_INT08U);
    }
    return (rem);
}


/*
*********************************************************************************************************
*                                           BCH_EvalPoly()
*
* Description : Evaluate polynomial at Galois field element alpha^pwr.
*
* Argument(s) : poly        Polynomial to evaluate.
*
*               pwr         Power of alpha at which polynomial will be evaluated.
*
* Return(s)   : none.
*
* Caller(s)   : BCH_CalcSyndrome().
*
* Note(s)     : none.
*********************************************************************************************************
*/

static  BCH_GF_POLY  BCH_EvalPoly (BCH_GF_POLY  poly,
                                   CPU_INT08U   pwr)
{
    BCH_GF_POLY      mask;
    BCH_GF_POLY_PWR  pwr_add;
    CPU_INT08U       pwr_poly;
    BCH_GF_POLY      sum;


    mask     = DEF_BIT_00;
    pwr_add  = 0u;
    pwr_poly = 0u;
    sum      = 0u;
    while (pwr_poly < BCH_m) {
        if (DEF_BIT_IS_SET(poly, mask) == DEF_YES) {
            sum ^= BCH_GF_Tbl[pwr_add];
        }

        mask <<= 1;
        pwr_poly++;

        pwr_add += (BCH_GF_POLY_PWR)pwr;
    }

    return (sum);
}
